#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Determine actual bytes to preview (min of requested and available)
    size_t available = storage.size();
    size_t to_preview = std::min(bytes_to_preview, available);

    // Create result vector with appropriate size
    std::vector<uint8_t> result(to_preview);

    // Peek data without consuming (doesn't advance read pointer)
    if (to_preview > 0) {
        storage.peek(result.data(), to_preview);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    // Get the amount of readable data
    status.readable_size = storage.size();
    // Get the amount of free space available for writing
    status.free_space = storage.free_size();
    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets
    storage.reset();
}
