#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Handle null pointers or zero-length regions - no overlap
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert to char pointers for byte-level arithmetic
    const char* src_begin = static_cast<const char*>(src);
    const char* src_end = src_begin + src_len;
    const char* dst_begin = static_cast<const char*>(dst);
    const char* dst_end = dst_begin + dst_len;

    // Two regions overlap if:
    // - src starts before dst ends, AND
    // - dst starts before src ends
    return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Validate inputs
    if (!destination || !source || length == 0) {
        return false;
    }

    // Check for overlap - memcpy requires non-overlapping regions
    if (check_regions_overlap(source, length, destination, length)) {
        return false;
    }

    // Regions don't overlap, safe to use memcpy
    std::memcpy(destination, source, length);
    return true;
}
